import z from 'zod';

import { log } from '@/shared/log';
import { executeFetch } from './fetch';
import { safeParseResponse } from '@/shared/neverthrow/fetch';
import { TOOL_PARAMS } from '@/shared/descriptions';
import { RequestMethod } from '@/shared/request/types';

import type { JsonStringifyValue } from '@/shared/neverthrow/json/types';
import type { Wallets } from '@/wallet';
import type { GlobalFlags } from '@/types';

const AGENTCASH_SEARCH_URL =
  process.env.AGENTCASH_SEARCH_URL ?? 'https://agentcash.dev/api/search';

export const searchSchema = z.object({
  query: z.string().min(1).describe(TOOL_PARAMS.search.query),
  broad: z.boolean().optional().describe(TOOL_PARAMS.search.broad),
  limit: z
    .number()
    .int()
    .min(1)
    .max(50)
    .optional()
    .describe(TOOL_PARAMS.search.limit),
  page: z.number().int().min(1).optional().describe(TOOL_PARAMS.search.page),
});

export type SearchInput = z.input<typeof searchSchema>;

export interface SearchOptions {
  surface: string;
  wallets: Wallets;
  flags: GlobalFlags;
}

export type SearchResult =
  | { success: true; results: JsonStringifyValue }
  | {
      success: false;
      cause: string;
      message: string;
      details?: JsonStringifyValue;
    };

/**
 * Search for relevant paid API services by natural language query.
 * Calls the agentcash search API with SIWX auth via executeFetch.
 */
export async function search(
  args: SearchInput,
  options: SearchOptions
): Promise<SearchResult> {
  const parsed = searchSchema.safeParse(args);
  if (!parsed.success) {
    return {
      success: false,
      cause: 'invalid_input',
      message: parsed.error.message,
    };
  }

  const { surface, wallets, flags } = options;

  log.info(`[search] Searching for: ${parsed.data.query}`);

  const fetchResult = await executeFetch(
    {
      url: AGENTCASH_SEARCH_URL,
      method: RequestMethod.POST,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        query: parsed.data.query,
        ...(parsed.data.broad ? { broad: true } : {}),
        ...(parsed.data.limit ? { limit: parsed.data.limit } : {}),
        ...(parsed.data.page ? { page: parsed.data.page } : {}),
      }),
    },
    {
      surface,
      wallets,
      flags,
      params: {},
    }
  );

  if (fetchResult.isErr()) {
    return {
      success: false,
      cause: fetchResult.error.cause,
      message: fetchResult.error.message,
    };
  }

  const { response } = fetchResult.value;

  if (!response.ok) {
    const parseResult = await safeParseResponse(surface, response);
    return {
      success: false,
      cause: 'http',
      message: `Search API returned ${response.status}: ${response.statusText}`,
      details: parseResult.match(
        data =>
          data.type === 'json' || data.type === 'text'
            ? (data.data as JsonStringifyValue)
            : undefined,
        () => undefined
      ),
    };
  }

  const parseResult = await safeParseResponse(surface, response);

  if (parseResult.isErr()) {
    return {
      success: false,
      cause: parseResult.error.cause,
      message: parseResult.error.message,
    };
  }

  const parsedResponse = parseResult.value;

  return {
    success: true,
    results:
      parsedResponse.type === 'json' || parsedResponse.type === 'text'
        ? (parsedResponse.data as JsonStringifyValue)
        : { type: parsedResponse.type },
  };
}
